    _escapeTime(
        x,
        y,
        iterations,
        bailout,
        (zx, zy, cx, cy) =>
            ((zx * zx - zy * zy).abs() + cx, 2.0 * zx * zy + cy));
(double r, double g, double b) _cpu_buffalo(
