import 'dart:async';
import 'dart:isolate';

import 'cpu_render_isolate.dart';

/// A long-lived isolate for CPU tile rendering.
///
/// Spawning an isolate per tile (Isolate.run) is far too slow on mobile.
/// This worker keeps one isolate alive and processes tile jobs sequentially.
class CpuTileWorker {
  CpuTileWorker._(this._isolate, this._sendPort, this._sub);

  final Isolate _isolate;
  final SendPort _sendPort;
  final StreamSubscription _sub;

  static Future<CpuTileWorker> spawn() async {
    final receive = ReceivePort();
    final handshake = Completer<SendPort>();

    final sub = receive.listen((msg) {
      if (msg is SendPort && !handshake.isCompleted) {
        handshake.complete(msg);
      }
    });

    final isolate = await Isolate.spawn(_entry, receive.sendPort);
    final sendPort = await handshake.future;

    return CpuTileWorker._(isolate, sendPort, sub);
  }

  Future<CpuTileRenderResponse> renderTile(CpuTileRenderRequest req) async {
    final rp = ReceivePort();
    _sendPort.send((req, rp.sendPort));
    final msg = await rp.first;
    rp.close();
    return msg as CpuTileRenderResponse;
  }

  void dispose() {
    _sub.cancel();
    _isolate.kill(priority: Isolate.immediate);
  }
}

void _entry(SendPort mainSendPort) {
  final commands = ReceivePort();
  mainSendPort.send(commands.sendPort);

  commands.listen((msg) {
    final (CpuTileRenderRequest req, SendPort replyTo) = msg as (CpuTileRenderRequest, SendPort);
    final resp = renderCpuTileInIsolate(req);
    replyTo.send(resp);
  });
}

import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

import 'package:flutter_fractals/core/modules/builders/escape_time_catalog.dart';
import 'package:flutter_fractals/features/renderer/cpu_formulas.dart';
import 'package:flutter_fractals/features/renderer/cpu_fractal_renderer.dart';

void main() {
  group('CPU Formula Registry', () {
    test('resolves every escape-time catalog module id', () {
      final unresolved = <String>[];
      for (final cfg in escapeTimeCatalog) {
        final formula = cpuFormulaForModuleId(cfg.id);
        final color = formula(0.0, 0.0, 32, 4.0, Vector2.zero());
        final valid =
            color.$1.isFinite && color.$2.isFinite && color.$3.isFinite;
        if (!valid) {
          unresolved.add(cfg.id);
        }
      }
      expect(
        unresolved,
        isEmpty,
        reason:
            'CPU formula resolver produced invalid output for: ${unresolved.join(', ')}',
      );
    });

    test('non-mandelbrot formulas differ from Mandelbrot baseline', () async {
      const width = 64;
      const height = 64;

      // One standard view for consistent comparisons.
      final viewPan = Vector2(-0.5, 0.0);
      const viewZoom = 3.0;
      const iterations = 80;
      const bailout = 4.0;
      final juliaC = Vector2(-0.8, 0.156);

      final baseline = await renderCpuFrame(
        moduleId: 'mandelbrot',
        viewPan: viewPan,
        viewZoom: viewZoom,
        iterations: iterations,
        bailout: bailout,
        juliaC: juliaC,
        width: width,
        height: height,
        sampleCount: 1,
      );

      for (final cfg in escapeTimeCatalog) {
        if (cfg.id == 'mandelbrot') continue;

        final frame = await renderCpuFrame(
          moduleId: cfg.id,
          viewPan: viewPan,
          viewZoom: viewZoom,
          iterations: iterations,
          bailout: bailout,
          juliaC: juliaC,
          width: width,
          height: height,
          sampleCount: 1,
        );

        int diff = 0;
        final total = width * height;
        for (int i = 0; i < frame.rgba.length; i += 4) {
          final dr = (frame.rgba[i] - baseline.rgba[i]).abs();
          final dg = (frame.rgba[i + 1] - baseline.rgba[i + 1]).abs();
          final db = (frame.rgba[i + 2] - baseline.rgba[i + 2]).abs();
          if (dr + dg + db >= 10) diff++;
        }

        final ratio = diff / total;
        expect(
          ratio,
          greaterThan(0.05),
          reason:
              'CPU formula for ${cfg.id} is too similar to Mandelbrot baseline (diffRatio=${ratio.toStringAsFixed(3)}).',
        );
      }
    }, timeout: const Timeout(Duration(minutes: 2)));

    test('renders non-black ratio above 1%', () async {
      const width = 64;
      const height = 64;

      final viewPan = Vector2(-0.5, 0.0);
      const viewZoom = 3.0;
      const iterations = 80;
      const bailout = 4.0;
      final juliaC = Vector2(-0.8, 0.156);

      for (final cfg in escapeTimeCatalog) {
        final frame = await renderCpuFrame(
          moduleId: cfg.id,
          viewPan: viewPan,
          viewZoom: viewZoom,
          iterations: iterations,
          bailout: bailout,
          juliaC: juliaC,
          width: width,
          height: height,
          sampleCount: 1,
        );

        int nonBlack = 0;
        for (int i = 0; i < frame.rgba.length; i += 4) {
          if (frame.rgba[i] > 8 ||
              frame.rgba[i + 1] > 8 ||
              frame.rgba[i + 2] > 8) {
            nonBlack++;
          }
        }
        final ratio = nonBlack / (width * height);
        expect(
          ratio,
          greaterThan(0.01),
          reason:
              '${cfg.id} produced too many black pixels (nonBlackRatio=${ratio.toStringAsFixed(3)}).',
        );
      }
    }, timeout: const Timeout(Duration(minutes: 2)));
  });
}

import 'dart:math' as math;
import 'dart:typed_data';

import 'package:vector_math/vector_math.dart' show Vector2;

import 'cpu_formulas.dart';

/// Message used to request a CPU frame render from an isolate.
final class CpuRenderRequest {
  const CpuRenderRequest({
    required this.moduleId,
    required this.panX,
    required this.panY,
    required this.zoom,
    required this.iterations,
    required this.bailout,
    required this.juliaCX,
    required this.juliaCY,
    required this.width,
    required this.height,
    required this.sampleCount,
  });

  final String moduleId;
  final double panX;
  final double panY;
  final double zoom;
  final int iterations;
  final double bailout;
  final double juliaCX;
  final double juliaCY;
  final int width;
  final int height;
  final int sampleCount;
}

final class CpuRenderResponse {
  const CpuRenderResponse({
    required this.rgba,
    required this.width,
    required this.height,
  });

  /// RGBA8888 bytes.
  final Uint8List rgba;
  final int width;
  final int height;
}

/// Top-level entrypoint suitable for [Isolate.run].
CpuRenderResponse renderCpuFrameInIsolate(CpuRenderRequest req) {
  final bytes = _renderRect(
    moduleId: req.moduleId,
    panX: req.panX,
    panY: req.panY,
    zoom: req.zoom,
    iterations: req.iterations,
    bailout: req.bailout,
    juliaCX: req.juliaCX,
    juliaCY: req.juliaCY,
    // Full viewport
    fullWidth: req.width,
    fullHeight: req.height,
    // Tile == full
    x0: 0,
    y0: 0,
    w: req.width,
    h: req.height,
    sampleCount: req.sampleCount,
  );
  return CpuRenderResponse(rgba: bytes, width: req.width, height: req.height);
}

final class CpuTileRenderRequest {
  const CpuTileRenderRequest({
    required this.moduleId,
    required this.panX,
    required this.panY,
    required this.zoom,
    required this.iterations,
    required this.bailout,
    required this.juliaCX,
    required this.juliaCY,
    required this.fullWidth,
    required this.fullHeight,
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
    required this.sampleCount,
  });

  final String moduleId;
  final double panX;
  final double panY;
  final double zoom;
  final int iterations;
  final double bailout;
  final double juliaCX;
  final double juliaCY;

  final int fullWidth;
  final int fullHeight;
  final int x0;
  final int y0;
  final int w;
  final int h;
  final int sampleCount;
}

final class CpuTileRenderResponse {
  const CpuTileRenderResponse({
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
    required this.rgba,
  });

  final int x0;
  final int y0;
  final int w;
  final int h;
  final Uint8List rgba;
}

CpuTileRenderResponse renderCpuTileInIsolate(CpuTileRenderRequest req) {
  final bytes = _renderRect(
    moduleId: req.moduleId,
    panX: req.panX,
    panY: req.panY,
    zoom: req.zoom,
    iterations: req.iterations,
    bailout: req.bailout,
    juliaCX: req.juliaCX,
    juliaCY: req.juliaCY,
    fullWidth: req.fullWidth,
    fullHeight: req.fullHeight,
    x0: req.x0,
    y0: req.y0,
    w: req.w,
    h: req.h,
    sampleCount: req.sampleCount,
  );

  return CpuTileRenderResponse(
    x0: req.x0,
    y0: req.y0,
    w: req.w,
    h: req.h,
    rgba: bytes,
  );
}

Uint8List _renderRect({
  required String moduleId,
  required double panX,
  required double panY,
  required double zoom,
  required int iterations,
  required double bailout,
  required double juliaCX,
  required double juliaCY,
  required int fullWidth,
  required int fullHeight,
  required int x0,
  required int y0,
  required int w,
  required int h,
  required int sampleCount,
}) {
  final centerX = panX;
  final centerY = panY;
  final z = zoom <= 0 ? 1.0 : zoom;

  // Mandelbrot viewport baseline:
  // x in [-2.0, 1.0] (width 3.0) and y in [-1.5, 1.5] (height 3.0).
  // Using half-range 1.5 keeps the set correctly proportioned.
  final scale = 1.5 / z;
  final aspect = fullWidth / fullHeight;

  final bytes = Uint8List(w * h * 4);
  final samplesPerAxis = math.max(1, math.sqrt(sampleCount).round());
  final totalSamples = samplesPerAxis * samplesPerAxis;

  final juliaC = Vector2(juliaCX, juliaCY);
  final formula = cpuFormulaForModuleId(moduleId);

  for (int ty = 0; ty < h; ty++) {
    final y = y0 + ty;
    for (int tx = 0; tx < w; tx++) {
      final x = x0 + tx;

      double rAcc = 0;
      double gAcc = 0;
      double bAcc = 0;

      for (int sy = 0; sy < samplesPerAxis; sy++) {
        for (int sx = 0; sx < samplesPerAxis; sx++) {
          final subX = (x + (sx + 0.5) / samplesPerAxis) / (fullWidth - 1);
          final subY = (y + (sy + 0.5) / samplesPerAxis) / (fullHeight - 1);
          final nx = subX * 2.0 - 1.0;
          final ny = subY * 2.0 - 1.0;

          final cx = centerX + nx * scale * aspect;
          final cy = centerY + ny * scale;

          final color = formula(cx, cy, iterations, bailout, juliaC);
          rAcc += color.$1;
          gAcc += color.$2;
          bAcc += color.$3;
        }
      }

      final idx = (ty * w + tx) * 4;
      bytes[idx + 0] = (rAcc / totalSamples).clamp(0, 255).round();
      bytes[idx + 1] = (gAcc / totalSamples).clamp(0, 255).round();
      bytes[idx + 2] = (bAcc / totalSamples).clamp(0, 255).round();
      bytes[idx + 3] = 255;
    }
  }

  return bytes;
}

